 22→async function updateRepliesInDb(replies) {
 23→    const connection = await POOL.getConnection();
 24→    try {
 25→        for (const reply of replies) {
 26→            if (reply.status === 400) {
 27→
 28→                await connection.execute('UPDATE replies SET status = ? WHERE id = ?', [reply.status, reply.id]);
 29→
 30→            } else if (reply.status === 200) {
 31→
 32→                // Get existing notes in database  to keep them in case they have been deleted from the website 
 33→                const [existingNotesRow] = await connection.execute('SELECT notes FROM replies WHERE id = ?', [reply.id]);
 34→                const existingNotes = JSON.parse(existingNotesRow[0].notes);
 35→                const newNotes = reply.notes;
 36→
 37→                // If new notes are less in number than existing notes in database don't update notes
 38→                if (newNotes.length >= existingNotes.length) {
 39→                    const commonNotes = existingNotes.filter((note) => newNotes.find((n) => (n.comment === note.comment && n.user === note.user)));
 40→
 41→                    // In case no existing notes have been deleted go ahead and overwrite notes
 42→                    if (commonNotes.length === existingNotes.length) {
 43→
 44→                        await connection.execute('UPDATE replies SET notes = ?, score = ? WHERE id = ?', [JSON.stringify(newNotes), reply.score, reply.id]);
 45→
 46→                    } else {
 47→
 48→                        // If existing notes have been deleted combine notes before overwriting
 49→                        const combinedNotes = [...existingNotes, ...newNotes.filter((n) => !existingNotes.find((note) => (n.comment === note.comment && n.user === note.user)))];
 50→                        await connection.execute('UPDATE replies SET notes = ?, score = ? WHERE id = ?', [JSON.stringify(combinedNotes), reply.score, reply.id]);
 51→                    }
 52→                }
 53→            } else {
 54→                // Only update score
 55→                await connection.execute('UPDATE replies score = ? WHERE id = ?', [reply.score, reply.id]);
 56→            }
 57→        }
 58→
 59→        connection.release();
 60→        return `${replies.length} replies updated successfully!`;
 61→    } catch (error) {
 62→        connection.release();
 63→        console.error('Error updating replies:', error);
 64→        return error;
 65→    }
 66→}
