102→                        const profileValues = [d.id, profile.rip];
103→                        await connection.execute(profileInsertSql, profileValues);
104→                    }
105→                    // Insert 404 and 403 status
106→                    else if (profile.status === 404 || profile.status === 403 || profile.status == 500) {
107→                        const profileInsertSql = 'INSERT INTO profiles (topic_id, status) VALUES (?, ?)';
108→                        const profileValues = [d.id, profile.status];
