281→/**
282→ * Recursively checks an object for `undefined` values and returns the name of the first key
283→ * with an `undefined` value.
284→ *
285→ * @param {object} obj - The object to check.
286→ * @param {string} [parentKey] - Internal use for recursion; you don't need to provide this.
287→ * @returns {string|null} - The name of the first key with an `undefined` value, or `null` if none found.
288→ */
289→function findUndefinedKey(obj, parentKey) {
290→    for (const key in obj) {
291→        if (obj.hasOwnProperty(key)) {
292→            const value = obj[key];
293→
294→            if (value === undefined) {
295→                return parentKey ? `${parentKey}.${key}` : key;
296→            } else if (typeof value === 'object' && !Array.isArray(value)) {
297→                const nestedKey = findUndefinedKey(value, parentKey ? `${parentKey}.${key}` : key);
298→                if (nestedKey !== null) {
299→                    return nestedKey;
300→                }
301→            }
302→        }
303→    }
304→    return null;
305→}
