375→/**
376→ * Insert an array of notes into the 'notes' table and close the connection.
377→ *
378→ * @param {Array} notes - An array of note objects.
379→ * @returns {Promise} A promise that resolves when all notes are inserted and the connection is closed.
380→ */
381→async function insertNotes(notes) {
382→    const connection = await POOL.getConnection();
383→    try {
384→        // Using a transaction for atomicity
385→        await connection.beginTransaction();
386→
387→        // Iterate through each note and insert into the 'notes' table
388→        const insertPromises = notes.map(async (note) => {
389→            const { user, comment, reply_id, position } = note;
390→
391→            // SQL query to insert a note
392→            const query = 'INSERT INTO notes (user, comment, reply_id, position) VALUES (?, ?, ?, ?)';
393→
394→            // Execute the query
395→            await connection.execute(query, [user, comment, reply_id, position]);
396→        });
397→
398→        // Wait for all insert operations to complete
399→        await Promise.all(insertPromises);
400→
401→        // Commit the transaction
402→        await connection.commit();
403→
404→        console.log('Notes inserted successfully!');
405→    } catch (error) {
406→        // Rollback the transaction if an error occurs
407→        await connection.rollback();
408→        console.error('Error inserting notes:', error.message);
409→    } finally {
410→        // Close the connection regardless of success or failure
411→        await connection.release();
412→        console.log('Connection closed.');
413→    }
414→}
