  1→const axios = require('axios');
  2→const https = require('https');
  3→
  4→// Create an https agent that doesn't reject unauthorized certificates
  5→// This is needed because qbn.com has an incomplete SSL certificate chain
  6→const httpsAgent = new https.Agent({
  7→    rejectUnauthorized: false
  8→});
