 10→/**
 11→ * Fetches pages within a specified range and returns an array of fetched responses.
 12→ * @param {string} url - The url to fetch
 13→ * @returns {object} The fetched response
 14→ */
 15→async function fetchPage(url) {
 16→    try {
 17→
 18→        const response = await axios.get(url, { httpsAgent });
 19→        return response;
 20→
 21→    } catch (error) {
 22→
 23→        console.error(`Error fetching page ${url}, error: ${error.message}`);
 24→
 25→        // Return 404 errors, we also want to store deleted pages
 26→        // 403 erros for profile pages like '/services/'
 27→        const status = error.response.status
 28→        if (status === 404 || status == 403 || status == 500) {
 29→            return error.response;
 30→        }
 31→
 32→        throw new Error(error);
 33→    }
 34→}
