 36→/**
 37→ * Fetches pages within a specified range and returns an array of fetched responses.
 38→ * 
 39→ * @param {string} baseUrl - The base url to use
 40→ * @param {number} startId - The page id  to start scraping from.
 41→ * @param {number} maxId - The maximum page id number to scrape up to.
 42→ * @returns {Array} An array of fetched responses for each page.
 43→ */
 44→async function fetchPages(baseUrl, startId, maxId) {
 45→    const fetchedData = []; // Initialize an array to store fetched data
 46→
 47→    for (let id = startId; id <= maxId; id++) {
 48→        const url = `${baseUrl}${id}/`; //  https://qbn.com/replies/1/ or https://qbn.com/topics/1/ 
 49→
 50→        try {
 51→            // Make a GET request to the url
 52→            const response = await axios.get(url, { httpsAgent });
 53→
 54→            // Add the page response object to the scrapedData array
 55→            fetchedData.push(response);
 56→
 57→        } catch (error) {
 58→            // Log error and continue fetching
 59→            console.error(`Error fetching id:${id} from url:${url}. Error:${error.message}`);
 60→            fetchedData.push(error.response);
 61→        }
 62→    }
 63→    return fetchedData; // Return the array of scraped data
 64→}
