 66→/**
 67→ * Fetches pages by providing an ID, continuing until encountering a specified number of consecutive 404 responses or a maximum number of total requests.
 68→ * 
 69→ * @param {string} baseUrl - The url to append before the ID
 70→ * @param {number} idToStart - The starting ID for page scraping.
 71→ * @param {number} maxTotalRequests - The maximum number of total requests to make.
 72→ * @param {number} maxConsecutive404 - The maximum number of consecutive 404 responses allowed before stopping.
 73→ * @returns {Promise<(string | null)[]>} - An array of scraped page data with null markers for deleted pages.
 74→ */
 75→async function autoFetchPagesById(baseUrl, idToStart, maxTotalRequests, maxConsecutive404) {
 76→    let resultArray = [];
 77→    let consecutive404Count = 0;
 78→    let totalRequests = 0;
 79→
 80→    // Fetch pages 404 responses included if under maxConsecutive404
 81→    while (totalRequests < maxTotalRequests && consecutive404Count < maxConsecutive404) {
 82→        const url = `${baseUrl}${idToStart}/`;
 83→
 84→        try {
 85→            const response = await axios.get(url, { httpsAgent });
 86→            totalRequests++;
 87→
 88→            if (response.status === 200) {
 89→                resultArray.push(response);
 90→                consecutive404Count = 0; // Reset consecutive 404 count
 91→            } else {
 92→                // Handle other HTTP status codes if needed
 93→                console.log(`Unexpected status code: ${response.status}`);
 94→            }
 95→
 96→            idToStart++;
 97→
 98→        } catch (error) {
 99→            // Handle the error and include the error response in the resultArray
100→            if (error.response && error.response.status === 404) {
101→                totalRequests++;
102→                resultArray.push(error.response); // Add a marker for deleted page
103→                consecutive404Count++;
104→                idToStart++;
105→
106→            } else {
107→                console.error('Error:', error);
108→                throw new Error(error)
109→                break; // Exit loop on error
110→            }
111→        }
112→    }
113→
114→    // Clean array by removing consecutive 404 markers from the end
115→    for (let i = resultArray.length - 1; i >= 0; i--) {
116→
117→        // Stop removing 404 markers at the first non 404 response
118→        if (resultArray[i] !== null && (resultArray[i].status !== 404)) {
119→            break;
120→        }
121→
122→        // Remove 404 markers from the bottom
123→        if (resultArray[i] === null || (resultArray[i].status === 404)) {
124→            resultArray.pop();
125→        }
126→
127→    }
128→
129→    return resultArray;
130→}
