135→ * @param {array} urls - The list of urls to fetch
136→ * @returns {Array} An array of fetched responses for each url.
137→ */
138→async function fetchPagesFromArray(urls) {
139→    const fetchedData = []; // Initialize an array to store fetched data
140→
141→    for (const url of urls) {
142→        try {
143→            const response = await axios.get(url, { httpsAgent });
144→
145→            // Add the topicData object to the scrapedData array
146→            fetchedData.push(response);
