238→function getTopicType(ntUrl, urlHasTitle, titleFromHtml) {
239→
240→    if (ntUrl != undefined) {
241→        return TYPE_NT;
242→    }
243→
244→    // If it doesn't have a title in the url and doesn't have a title in the html it's a profile
245→    // The thread '/ / / / / / / / / / / / / /'  id:697764 has a title in the html but not in the url
246→    if (!urlHasTitle && titleFromHtml == "") {
