252→/**
253→ * Handles fetching a processing a profile url
254→ * 
255→ * @param {string} url - The url to fetch and process
256→ * @returns A profile data object
257→ */
258→async function scrapeProfile(url) {
259→    const response = await fetchPage(url);
260→    const data = processProfile(response);
261→    return data;
