264→/**
265→ * Process scraped data using Cheerio.
266→ * 
267→ * @param {object} response - The axios get response object https://axios-http.com/docs/res_schema
268→ * @returns A data object
269→ */
270→function processProfile(response) {
271→    // Return only status if status is 404
272→    const responseStatus = response.status;
273→    if (responseStatus === 404 || responseStatus === 403 || responseStatus === 500) {
274→        return { status: responseStatus }
275→    }
276→
277→
278→    const $ = cheerio.load(response.data)
279→    // Check if user is deleted
280→    const rip = $("#main > p:nth-child(2)").text()
281→    if (rip != "") {
282→        const ripDate = $("#main > p:nth-child(3)").text()
283→        return { rip: ripDate }
284→    }
285→    // Extract 'invited by user' or 'certified by user', blank if none.
286→    const endorsement = extractEndorsement($);
287→    const { endorsementStatus, endorsedBy } = extractEndorsementInfo(endorsement);
288→
289→    const profile = {
290→        name: $("#main > ul.details > li.name").text().trim(),
291→        since: $("#main > h1 > small:nth-child(2)").text().split(' ')[1],
292→        location: $("#main > ul.details > li.location").text(),
293→        url: $("#main > ul.details > li.url").text(),
294→        avatar: $("#main > div").attr("data-url") ?? '',
295→        endorsementStatus: endorsementStatus,
296→        endorsedBy: endorsedBy,
297→        uncertified: $("#main > h1 > small.uncertified > a").text(),
298→        bio: $("#main > ul.thread.replies > li:nth-child(1) > dl > dd").html()
299→    }
300→    return profile
301→}
302→
303→/**
304→ * Extracts the text 'invited by user' or 'certified by user' from a parsed cheerio object.
305→ * 
306→ * @param {cheerio} $ - The cheerio parsed object.
307→ * @returns {string|null} - The extracted text or null if not found.
308→ */
309→function extractEndorsement($) {
310→    const invitedByElement = $('small.invited-by');
311→    if (invitedByElement.length > 0) {
312→        return invitedByElement.text();
313→    }
314→    return null; // Return null if the tag is not found.
315→}
316→
317→/**
318→ * Extracts the endorsement status and username from a given text.
319→ * 
320→ * @param {string} text - The text to parse, like "invited by username" or "certified by username".
321→ * @returns {Object} - An object with 'certificationStatus' and 'certifiedBy' properties.
322→ */
323→function extractEndorsementInfo(text) {
324→    text = text ?? '';
325→    const match = text.match(/(invited|certified) by (\w+)/) || [];
326→    const [_, endorsementStatus, endorsedBy] = match;
327→    return { endorsementStatus: endorsementStatus || '', endorsedBy: endorsedBy || '' };
328→}
329→
330→/**
331→ * Checks if url is "/topic/number/" or "topic/number-title/" 
332→ * 
333→ * @param {string} url - The topic page url
334→ * @returns boolean true if it has title false if it doesn't
335→ */
336→function getUrlHasTitle(url) {
337→    // Regular expression to match the pattern
338→    const urlPattern = /^https:\/\/(www\.)?qbn\.com\/topics\/\d+\/?(\?.*)?$/;
339→    return !urlPattern.test(url)
340→}
341→
342→/**
343→ * Retrieves title from the topic url, get the text after topic id
344→ * 
345→ * @param {string} url - The topic page url
346→ */
347→function getTopicTitleFromUrl(url) {
348→    // Define a regular expression to match the URL pattern.
349→    const regex = /(?:www\.)?qbn\.com\/topics\/([^\/]+)/;
350→    // Attempt to match the URL against the pattern.
351→    const match = url.match(regex)
352→
353→    if (match) {
354→        const topicOrID = match[1];
355→        // Check if the extracted string contains a dash ("-")
356→        if (topicOrID.includes("-")) {
357→            // If it does, return the text after the ID and the first dash
358→            return topicOrID.split('-').slice(1).join('-');
359→        } else {
360→            // If no dash is found, return the ID
361→            return topicOrID;
362→        }
363→    }
364→
365→    // Return null or an appropriate value for cases where there's no match.
366→    return null;
367→}
