244→
245→    // Check everything but htmlComment since not all db rows have that value yet
246→    const keys = ["comment", "user", "replyId", "position"]
247→
248→    // Iterate through the specified keys
249→    for (let key of keys) {
250→        // Compare values for each key
251→        if (note1[key] !== note2[key]) {
252→            return false; // Return false if any value is different
253→        }
254→    }
255→
256→    // If all key values are the same, return true
257→    return true;
258→}
259→/**
260→ * Compare two objects for equality of keys and values.
261→ * @param {Object} obj1 - The first object.
262→ * @param {Object} obj2 - The second object.
263→ * @returns {boolean} - True if the objects have the same keys and values, false otherwise.
264→ */
265→function areObjectsEqual(obj1, obj2) {
266→    const keys1 = Object.keys(obj1);
267→    const keys2 = Object.keys(obj2);
268→
269→    // Check if the number of keys is the same
270→    if (keys1.length !== keys2.length) {
271→        return false;
272→    }
273→
274→    // Check if all keys in obj1 have corresponding keys in obj2 and values are equal
275→    for (let key of keys1) {
276→        if (obj1[key] !== obj2[key]) {
277→            return false;
278→        }
279→    }
280→
281→    // If all checks pass, the objects are equal
282→    return true;
283→}
